 * Precision Score: TP / (TP + FP)
 */
 public static function precision(array $yTrue, array $yPred, $posLabel = 1): float {
 $tp = 0; $fp = 0;
 foreach ($yPred as $i => $pred) {
 if ($pred === $posLabel) {
 if (($yTrue[$i] ?? null) === $posLabel) $tp++;
 else $fp++;
 }
 }
 return ($tp + $fp) > 0 ? $tp / ($tp + $fp) : 0.0;
 }

