 $stateTokens = array_slice($tokens, $i, $this->order - 1);
 $nextToken = $tokens[$i + $this->order - 1];
 $state = implode(' ', $stateTokens);
 $this->transitions[$state][$nextToken] = ($this->transitions[$state][$nextToken] ?? 0) + 1;
 }
 }

