 private function pickWeightedToken(array $weights): string {
 $total = array_sum($weights);
 if ($total <= 0) {
 return array_key_first($weights);
 }

 $target = mt_rand(1, $total);
 $running = 0;
 foreach ($weights as $token => $weight) {
 $running += $weight;
 if ($running >= $target) {
 return (string)$token;
 }
 }

 return (string)array_key_first($weights);
 }

