$model->add(nn::Dropout(0.3));
$model->add(nn::Dense(4, 1, nn::getActivation('sigmoid')));
$model->compile(nn::getLoss('bce'), nn::getOptimizer('adam', 0.001));
$model->fit($X, $y, epochs: 100);
$output = $model->predict($X_test);
