 foreach ($this->enSuffixes as $suffix) {
 if (str_ends_with($token, $suffix)) {
 return mb_substr($token, 0, -mb_strlen($suffix));
 }
 }

 // Deep Hinglish stemming
 foreach ($this->hiSuffixes as $suffix) {
 if (str_ends_with($token, $suffix)) {
