 * Formula: z = (x - u) / s
 */
 public function standardScale(array $data): array {
 if (empty($data)) return $data;

 $count = count($data);
 $mean = array_sum($data) / $count;

 $variance = 0;
 foreach ($data as $x) {
 $variance += pow($x - $mean, 2);
