 private function softmax(array $scores): array {
 $max = max($scores); // For numerical stability
 $exp = array_map(fn($v) => exp($v - $max), $scores);
 $sum = array_sum($exp);
 return array_map(fn($v) => $v / ($sum ?: 1), $exp);
 }

